                source_webview,
                source_with_ancestry,
                origin,
                source_origin,
                *data,
            ),
            ScriptThreadMessage::UpdatePipelineId(
                parent_pipeline_id,
                browsing_context_id,
                webview_id,
                new_pipeline_id,
                reason,
            ) => self.handle_update_pipeline_id(
                parent_pipeline_id,
                browsing_context_id,
                webview_id,
                new_pipeline_id,
                reason,
                CanGc::from_cx(cx),
            ),
            ScriptThreadMessage::UpdateHistoryState(pipeline_id, history_state_id, url) => self
                .handle_update_history_state_msg(
                    pipeline_id,
                    history_state_id,
                    url,
                    CanGc::from_cx(cx),
                ),
